style:
/* ================================================
   WEBSITE-STYLE HERO — Co-Founder/Co-Worker Theme
   ================================================ */

.nxl-ws-hero {
    display: grid;
    grid-template-columns: 1.35fr 1fr;
    gap: 16px;
    margin-bottom: 0;
}

.nxl-ws-panel {
    position: relative;
    overflow: hidden;
    padding: 24px 26px 22px;
    border-radius: 20px;
    background: #ffffff;
    border: 1px solid rgba(33,77,187,0.13);
    box-shadow: 0 8px 24px rgba(33,77,187,0.08), inset 0 1px 0 rgba(255,255,255,0.90);
}

.nxl-ws-panel::before {
    content: "";
    position: absolute;
    left: 0; right: 0; top: 0;
    height: 5px;
    border-radius: 20px 20px 0 0;
}

.nxl-ws-panel > * { position: relative; z-index: 1; }

/* Blue (left — identity) */
.nxl-ws-panel-blue {
    border-top: 4px solid #214dbb;
    background:
        linear-gradient(135deg, rgba(33,77,187,0.05) 0%, rgba(255,255,255,0) 40%),
        #ffffff;
}
.nxl-ws-panel-blue::before {
    background: linear-gradient(90deg, #214dbb 0%, #4d75ff 55%, #e0a62f 100%);
}

/* Teal (right — operations / knowledge) */
.nxl-ws-panel-teal {
    border-top: 4px solid #0f8f7a;
    border-color: rgba(15,143,122,0.20);
    background:
        linear-gradient(135deg, rgba(15,143,122,0.055) 0%, rgba(255,255,255,0) 40%),
        #ffffff;
}
.nxl-ws-panel-teal::before {
    background: linear-gradient(90deg, #0f8f7a 0%, #16a37f 55%, #e0a62f 100%);
}

/* Purple (right — admin / platform / diagnostic) */
.nxl-ws-panel-purple {
    border-top: 4px solid #5c4bd8;
    border-color: rgba(92,75,216,0.20);
    background:
        linear-gradient(135deg, rgba(92,75,216,0.05) 0%, rgba(255,255,255,0) 40%),
        #ffffff;
}
.nxl-ws-panel-purple::before {
    background: linear-gradient(90deg, #5c4bd8 0%, #7c6ae8 55%, #e0a62f 100%);
}

/* Kicker pill */
.nxl-ws-kicker {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    margin-bottom: 14px;
    padding: 6px 12px;
    border-radius: 999px;
    background: #ffffff;
    border: 1px solid rgba(33,77,187,0.18);
    color: #214dbb;
    font-size: 0.76rem;
    font-weight: 800;
    letter-spacing: 0.12em;
    text-transform: uppercase;
}
.nxl-ws-kicker-teal  { border-color: rgba(15,143,122,0.22); color: #0f7b6b; }
.nxl-ws-kicker-purple { border-color: rgba(92,75,216,0.22); color: #4a3abf; }

/* Title row */
.nxl-ws-title-row {
    display: flex; align-items: center; gap: 14px; margin-bottom: 14px;
}
.nxl-ws-icon-box {
    width: 52px; height: 52px; border-radius: 16px;
    display: flex; align-items: center; justify-content: center;
    background: #214dbb;
    border: 1px solid rgba(255,255,255,0.30);
    box-shadow: 0 10px 22px rgba(33,77,187,0.22);
    flex-shrink: 0;
}
.nxl-ws-icon-box-teal {
    background: linear-gradient(135deg, #0f8f7a 0%, #16a37f 100%);
    box-shadow: 0 10px 22px rgba(15,143,122,0.22);
}
.nxl-ws-icon-box svg { width: 30px; height: 30px; }

.nxl-ws-h1 {
    margin: 0; color: #1d2756;
    font-size: 1.95rem; line-height: 1.14;
    font-weight: 850; letter-spacing: -0.6px;
}

/* Body */
.nxl-ws-lead {
    max-width: 680px; color: #5f6c8c;
    font-size: 0.96rem; line-height: 1.70; margin: 0 0 16px;
}
.nxl-ws-chips { display: flex; flex-wrap: wrap; gap: 7px; }
.nxl-ws-chip {
    padding: 5px 11px; border-radius: 999px;
    background: linear-gradient(180deg, #f3f8ff 0%, #eaf2ff 100%);
    border: 1px solid rgba(33,77,187,0.14);
    color: #214dbb; font-size: 0.76rem; font-weight: 700;
}

/* Right panel link list */
.nxl-ws-panel-title { margin: 0 0 14px; color: #1d2756; font-size: 1.30rem; font-weight: 850; letter-spacing: -0.3px; }
.nxl-ws-links { display: flex; flex-direction: column; gap: 8px; }

.nxl-ws-link-item {
    display: flex; align-items: center; gap: 12px;
    padding: 11px 14px; border-radius: 14px;
    background: linear-gradient(180deg, #f8fffe 0%, #f1fbf8 100%);
    border: 1px solid rgba(15,143,122,0.18);
    color: #1d2756; text-decoration: none;
    font-size: 0.92rem; font-weight: 700;
    transition: all 0.20s ease;
}
.nxl-ws-link-item:hover {
    background: linear-gradient(180deg, #eefbf8 0%, #e2f7f2 100%);
    border-color: rgba(15,143,122,0.38); color: #0f7b6b;
    text-decoration: none; transform: translateX(3px);
    box-shadow: 0 4px 12px rgba(15,143,122,0.10);
}

/* Purple variant link rows */
.nxl-ws-link-item-purple {
    background: linear-gradient(180deg, #faf9ff 0%, #f4f1ff 100%);
    border: 1px solid rgba(92,75,216,0.18);
}
.nxl-ws-link-item-purple:hover {
    background: linear-gradient(180deg, #f2eeff 0%, #e8e2ff 100%);
    border-color: rgba(92,75,216,0.38); color: #4a3abf;
    transform: translateX(3px); box-shadow: 0 4px 12px rgba(92,75,216,0.10);
}

/* Blue variant link rows (for Home workspace nav) */
.nxl-ws-link-item-blue {
    background: linear-gradient(180deg, #f8fbff 0%, #f0f5ff 100%);
    border: 1px solid rgba(33,77,187,0.18);
}
.nxl-ws-link-item-blue:hover {
    background: linear-gradient(180deg, #edf4ff 0%, #dfe9ff 100%);
    border-color: rgba(33,77,187,0.38); color: #173b96;
    transform: translateX(3px); box-shadow: 0 4px 12px rgba(33,77,187,0.10);
}

.nxl-ws-link-icon {
    width: 36px; height: 36px; min-width: 36px; border-radius: 11px;
    display: flex; align-items: center; justify-content: center;
    background: linear-gradient(135deg, #0f8f7a 0%, #16a37f 100%);
    color: #ffffff; font-size: 0.74rem; font-weight: 900;
}
.nxl-ws-link-icon-purple { background: linear-gradient(135deg, #5c4bd8 0%, #7c6ae8 100%); }
.nxl-ws-link-icon-blue   { background: linear-gradient(135deg, #214dbb 0%, #4d75ff 100%); }

.nxl-ws-link-desc {
    display: block; font-size: 0.73rem;
    color: #6d7f96; font-weight: 600; margin-top: 1px;
}

@media (max-width: 860px) {
    .nxl-ws-hero { grid-template-columns: 1fr; }
}

/* =========================================================
   DIGITZ AI Nexus Workspace Theme
   Finalized Blue + Teal Workspace Theme
   ========================================================= */

.nexus-ws {
    max-width: 1180px;
    margin: 0 auto;
    width: 100%;
    box-sizing: border-box;
    color: #102b67;
    font-family: inherit;
}

/* =========================
   Top Intelligence Panel
   ========================= */

.nexus-top-panel {
    position: relative;
    overflow: hidden;
    border-radius: 30px;
    padding: 30px;
    margin-bottom: 22px;
    background:
        radial-gradient(circle at 85% 18%, rgba(77, 200, 255, 0.30), transparent 30%),
        radial-gradient(circle at 92% 92%, rgba(0, 184, 148, 0.18), transparent 34%),
        linear-gradient(135deg, #082d8f 0%, #0b58d8 42%, #118fe5 78%, #33c6ec 100%);
    border: 1.5px solid rgba(77, 200, 255, 0.52);
    box-shadow:
        0 22px 52px rgba(33, 77, 187, 0.18),
        inset 0 1px 0 rgba(255, 255, 255, 0.25),
        inset 0 -30px 72px rgba(0, 42, 145, 0.16);
}

.nexus-top-panel::after {
    content: "";
    position: absolute;
    right: 0;
    bottom: 0;
    width: 42%;
    height: 7px;
    background: linear-gradient(
        90deg,
        transparent 0%,
        rgba(77, 200, 255, 0.70) 38%,
        rgba(0, 184, 148, 0.90) 100%
    );
    border-radius: 999px 0 0 0;
    box-shadow: 0 -8px 24px rgba(0, 184, 148, 0.18);
}

.nexus-top-orb {
    position: absolute;
    right: 38px;
    top: 28px;
    width: 150px;
    height: 150px;
    border-radius: 50%;
    background:
        radial-gradient(circle at 35% 30%, rgba(255, 255, 255, 0.28), transparent 34%),
        rgba(255, 255, 255, 0.08);
    border: 1px solid rgba(255, 255, 255, 0.28);
    box-shadow: inset 0 0 42px rgba(255, 255, 255, 0.18);
    display: flex;
    align-items: center;
    justify-content: center;
    color: rgba(255, 255, 255, 0.46);
    font-size: 98px;
    font-weight: 950;
    line-height: 1;
    pointer-events: none;
}

.nexus-top-content {
    position: relative;
    z-index: 2;
    max-width: 820px;
}

.nexus-kicker {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 7px 12px;
    border-radius: 999px;
    background: rgba(255, 255, 255, 0.15);
    border: 1px solid rgba(255, 255, 255, 0.34);
    color: #ffffff;
    font-size: 11px;
    font-weight: 950;
    letter-spacing: 0.10em;
    text-transform: uppercase;
    margin-bottom: 16px;
}

.nexus-kicker-dot {
    width: 8px;
    height: 8px;
    border-radius: 999px;
    background: #00b894;
    box-shadow: 0 0 18px rgba(0, 184, 148, 0.70);
}

.nexus-top-title {
    margin: 0;
    color: #ffffff;
    font-size: 40px;
    line-height: 1.12;
    font-weight: 950;
    letter-spacing: -0.045em;
    text-shadow: 0 10px 26px rgba(0, 35, 120, 0.28);
}

.nexus-top-lead {
    margin: 14px 0 0;
    max-width: 820px;
    color: rgba(255, 255, 255, 0.95);
    font-size: 17px;
    line-height: 1.55;
    font-weight: 750;
    text-shadow: 0 8px 22px rgba(0, 35, 120, 0.20);
}

.nexus-chip-row {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    margin-top: 22px;
}

.nexus-chip {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    min-height: 36px;
    padding: 8px 14px;
    border-radius: 999px;
    color: #ffffff;
    background: rgba(255, 255, 255, 0.16);
    border: 1px solid rgba(255, 255, 255, 0.50);
    font-size: 12px;
    font-weight: 900;
}

/* =========================
   Active Context Strip
   ========================= */

.nexus-context-grid {
    display: grid;
    grid-template-columns: 1.5fr repeat(3, minmax(160px, 1fr));
    gap: 12px;
    margin-bottom: 24px;
}

.nexus-context-card {
    min-height: 92px;
    padding: 18px;
    border-radius: 22px;
    background: linear-gradient(180deg, #ffffff 0%, #f8fbff 100%);
    border: 1.5px solid rgba(33, 119, 255, 0.34);
    box-shadow: 0 12px 28px rgba(33, 77, 187, 0.07);
    display: flex;
    align-items: center;
    gap: 12px;
    position: relative;
    overflow: hidden;
}

.nexus-context-card-primary {
    background:
        radial-gradient(circle at 100% 0%, rgba(77, 200, 255, 0.10), transparent 28%),
        linear-gradient(180deg, #ffffff 0%, #f8fbff 100%);
    border-color: rgba(33, 119, 255, 0.40);
    box-shadow: 0 12px 28px rgba(33, 77, 187, 0.08);
    gap: 14px;
}

.nexus-context-card-primary::before {
    content: "";
    position: absolute;
    left: 0;
    top: 0;
    bottom: 0;
    width: 5px;
    background: linear-gradient(180deg, #0b6cff, #4dc8ff);
}

.nexus-context-card-teal {
    background: linear-gradient(180deg, #ffffff 0%, #f1fffb 100%);
    border-color: rgba(0, 184, 148, 0.30);
    box-shadow: 0 12px 28px rgba(0, 184, 148, 0.08);
}

.nexus-context-card-teal-soft {
    background: linear-gradient(180deg, #ffffff 0%, #f1fffb 100%);
    border-color: rgba(0, 184, 148, 0.28);
    box-shadow: 0 12px 28px rgba(0, 184, 148, 0.06);
}

.nexus-context-icon {
    width: 42px;
    height: 42px;
    min-width: 42px;
    border-radius: 15px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #eef6ff;
    color: #0b6cff;
    font-size: 20px;
    font-weight: 950;
}

.nexus-context-icon-large {
    width: 48px;
    height: 48px;
    min-width: 48px;
    border-radius: 16px;
    color: #0b6cff;
    background: #eef6ff;
    font-size: 22px;
    border: 1px solid rgba(11, 108, 255, 0.14);
}

.nexus-context-icon-mint {
    background: #dffff6;
    color: #00b894;
}

.nexus-context-icon-teal {
    background: #ecfffb;
    color: #00b894;
}

.nexus-context-title {
    margin: 0;
    color: #102b67;
    font-size: 14px;
    font-weight: 950;
}

.nexus-context-title-large {
    font-size: 17px;
}

.nexus-context-text {
    margin: 5px 0 0;
    color: #526887;
    font-size: 12px;
    line-height: 1.45;
    font-weight: 750;
}

/* =========================
   Section Heading
   ========================= */

.nexus-section {
    display: flex;
    align-items: flex-end;
    justify-content: space-between;
    gap: 14px;
    margin: 0 0 12px;
    flex-wrap: wrap;
}

.nexus-section-badge {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 6px 10px;
    border-radius: 999px;
    background: #eef6ff;
    color: #0b60d8;
    border: 1px solid rgba(11, 108, 255, 0.18);
    font-size: 11px;
    font-weight: 950;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    margin-bottom: 8px;
}

.nexus-section-badge-teal {
    background: #ecfffb;
    color: #008c78;
    border-color: rgba(0, 184, 148, 0.22);
}

.nexus-section-title {
    margin: 0;
    color: #071d4f;
    font-size: 22px;
    line-height: 1.2;
    font-weight: 950;
    letter-spacing: -0.035em;
}

.nexus-section-title::after {
    content: "";
    display: inline-block;
    width: 36px;
    height: 4px;
    margin-left: 10px;
    border-radius: 999px;
    background: linear-gradient(90deg, #00b894, #4dc8ff);
    vertical-align: middle;
}

.nexus-section-text {
    margin: 6px 0 0;
    color: #526887;
    font-size: 13px;
    line-height: 1.45;
    font-weight: 700;
}

/* =========================
   Workspace Cards
   ========================= */

.nexus-card-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
    gap: 14px;
    margin-bottom: 24px;
}

.nexus-card {
    position: relative;
    min-height: 230px;
    padding: 22px;
    border-radius: 22px;
    background:
        radial-gradient(circle at 100% 0%, rgba(77, 163, 255, 0.16), transparent 30%),
        linear-gradient(180deg, #ffffff 0%, #f8fbff 100%);
    border: 1.5px solid rgba(33, 119, 255, 0.42);
    box-shadow:
        0 14px 32px rgba(33, 77, 187, 0.09),
        inset 0 1px 0 rgba(255, 255, 255, 0.78);
    color: inherit;
    text-decoration: none;
    display: block;
    overflow: hidden;
}

.nexus-card:hover {
    color: inherit;
    text-decoration: none;
}

.nexus-card::before {
    content: "";
    position: absolute;
    left: 0;
    right: 0;
    top: 0;
    height: 5px;
    background: linear-gradient(90deg, #0b6cff, #4dc8ff);
}

.nexus-card-purple::before {
    background: linear-gradient(90deg, #725cff, #0b6cff);
}

.nexus-card-teal::before {
    background: linear-gradient(90deg, #00b894, #4dc8ff);
}

.nexus-card-teal-bg {
    background: linear-gradient(180deg, #ffffff 0%, #f1fffb 100%);
    border-color: rgba(0, 184, 148, 0.32);
    box-shadow:
        0 14px 32px rgba(0, 184, 148, 0.08),
        inset 0 1px 0 rgba(255, 255, 255, 0.78);
}

.nexus-card-head {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    gap: 12px;
    margin-bottom: 14px;
}

.nexus-card-icon {
    width: 52px;
    height: 52px;
    border-radius: 18px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 23px;
    font-weight: 950;
    color: #0b6cff;
    background: #eef6ff;
}

.nexus-card-icon-purple {
    color: #725cff;
    background: #f4f1ff;
}

.nexus-card-icon-teal {
    color: #00b894;
    background: #ecfffb;
}

.nexus-card-arrow {
    width: 32px;
    height: 32px;
    border-radius: 999px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #214dbb;
    background: #ffffff;
    border: 1.5px solid rgba(33, 119, 255, 0.35);
    font-weight: 950;
}

.nexus-card-arrow-teal {
    color: #008c78;
    border-color: rgba(0, 184, 148, 0.32);
}

.nexus-card-title {
    margin: 0;
    color: #102b67;
    font-size: 18px;
    font-weight: 950;
}

.nexus-card-subtitle {
    margin-top: 4px;
    color: #264579;
    font-size: 13px;
    font-weight: 900;
}

.nexus-card-subtitle-teal {
    color: #008c78;
}

.nexus-card-text {
    margin: 7px 0 0;
    color: #526887;
    font-size: 12px;
    line-height: 1.55;
    font-weight: 700;
}

.nexus-tag-row {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    margin-top: 18px;
}

.nexus-tag {
    padding: 7px 11px;
    border-radius: 999px;
    background: #f3f8ff;
    color: #0b60d8;
    font-size: 11px;
    font-weight: 900;
    border: 1px solid rgba(33, 119, 255, 0.18);
}

.nexus-tag-purple {
    background: #f5f2ff;
    color: #5e49d8;
    border-color: transparent;
}

.nexus-tag-teal {
    background: #edfffb;
    color: #008c78;
    border-color: transparent;
}

.nexus-tag-teal-strong {
    background: #ecfffb;
    color: #008c78;
    border-color: transparent;
}

/* =========================
   Capabilities
   ========================= */

.nexus-capability-panel {
    padding: 22px;
    border-radius: 24px;
    background:
        radial-gradient(circle at 100% 0%, rgba(0, 184, 148, 0.06), transparent 24%),
        #ffffff;
    border: 1.5px solid rgba(33, 119, 255, 0.42);
    box-shadow:
        0 14px 32px rgba(33, 77, 187, 0.09),
        inset 0 1px 0 rgba(255, 255, 255, 0.78);
}

.nexus-capability-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(190px, 1fr));
    gap: 12px;
}

.nexus-capability-tile {
    display: flex;
    align-items: center;
    gap: 12px;
    min-height: 72px;
    padding: 14px;
    border-radius: 16px;
    background: #ffffff;
    border: 1.5px solid rgba(33, 119, 255, 0.30);
}

.nexus-capability-tile-teal {
    background: #f1fffb;
    border-color: rgba(0, 184, 148, 0.30);
}

.nexus-capability-icon {
    width: 38px;
    height: 38px;
    min-width: 38px;
    border-radius: 13px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #eef6ff;
    color: #0b6cff;
    font-size: 18px;
    font-weight: 950;
}

.nexus-capability-icon-teal {
    background: #dffff6;
    color: #00b894;
}

.nexus-capability-text {
    margin: 0;
    color: #102b67;
    font-size: 12px;
    line-height: 1.35;
    font-weight: 850;
}

/* =========================
   Responsive
   ========================= */

@media (max-width: 900px) {
    .nexus-context-grid {
        grid-template-columns: 1fr 1fr;
    }

    .nexus-top-orb {
        opacity: 0.35;
        right: 16px;
    }
}

@media (max-width: 640px) {
    .nexus-top-panel {
        padding: 24px;
    }

    .nexus-top-title {
        font-size: 32px;
    }

    .nexus-context-grid,
    .nexus-card-grid,
    .nexus-capability-grid {
        grid-template-columns: 1fr;
    }
}

/* ================================================
   WEBSITE-STYLE LIVE HERO — Co-Founder/Co-Worker Theme
   ================================================ */

.nxl-ws-hero {
    display: grid;
    grid-template-columns: 1.35fr 1fr;
    gap: 16px;
    margin-bottom: 0;
}

.nxl-ws-panel {
    position: relative;
    overflow: hidden;
    padding: 24px 26px 22px;
    border-radius: 20px;
    background: #ffffff;
    border: 1px solid rgba(33,77,187,0.13);
    box-shadow: 0 8px 24px rgba(33,77,187,0.08), inset 0 1px 0 rgba(255,255,255,0.90);
}

.nxl-ws-panel::before {
    content: "";
    position: absolute;
    left: 0;
    right: 0;
    top: 0;
    height: 5px;
    border-radius: 20px 20px 0 0;
}

.nxl-ws-panel > * {
    position: relative;
    z-index: 1;
}

/* Blue panel (left — main identity) */
.nxl-ws-panel-blue {
    border-top: 4px solid #214dbb;
    background:
        linear-gradient(135deg, rgba(33,77,187,0.05) 0%, rgba(255,255,255,0) 40%),
        #ffffff;
}

.nxl-ws-panel-blue::before {
    background: linear-gradient(90deg, #214dbb 0%, #4d75ff 55%, #e0a62f 100%);
}

/* Teal panel (right — quick access) */
.nxl-ws-panel-teal {
    border-top: 4px solid #0f8f7a;
    border-color: rgba(15,143,122,0.20);
    background:
        linear-gradient(135deg, rgba(15,143,122,0.055) 0%, rgba(255,255,255,0) 40%),
        #ffffff;
}

.nxl-ws-panel-teal::before {
    background: linear-gradient(90deg, #0f8f7a 0%, #16a37f 55%, #e0a62f 100%);
}

/* Kicker pill */
.nxl-ws-kicker {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    margin-bottom: 14px;
    padding: 6px 12px;
    border-radius: 999px;
    background: #ffffff;
    border: 1px solid rgba(33,77,187,0.18);
    color: #214dbb;
    font-size: 0.76rem;
    font-weight: 800;
    letter-spacing: 0.12em;
    text-transform: uppercase;
}

.nxl-ws-kicker-teal {
    border-color: rgba(15,143,122,0.22);
    color: #0f7b6b;
}

/* Title row */
.nxl-ws-title-row {
    display: flex;
    align-items: center;
    gap: 14px;
    margin-bottom: 14px;
}

.nxl-ws-icon-box {
    width: 52px;
    height: 52px;
    border-radius: 16px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #214dbb;
    border: 1px solid rgba(255,255,255,0.30);
    box-shadow: 0 10px 22px rgba(33,77,187,0.22);
    flex-shrink: 0;
}

.nxl-ws-icon-box svg {
    width: 30px;
    height: 30px;
}

.nxl-ws-h1 {
    margin: 0;
    color: #1d2756;
    font-size: 1.95rem;
    line-height: 1.14;
    font-weight: 850;
    letter-spacing: -0.6px;
}

/* Body */
.nxl-ws-lead {
    max-width: 680px;
    color: #5f6c8c;
    font-size: 0.96rem;
    line-height: 1.70;
    margin: 0 0 16px;
}

.nxl-ws-chips {
    display: flex;
    flex-wrap: wrap;
    gap: 7px;
}

.nxl-ws-chip {
    padding: 5px 11px;
    border-radius: 999px;
    background: linear-gradient(180deg, #f3f8ff 0%, #eaf2ff 100%);
    border: 1px solid rgba(33,77,187,0.14);
    color: #214dbb;
    font-size: 0.76rem;
    font-weight: 700;
}

/* Right panel — operations links */
.nxl-ws-panel-title {
    margin: 0 0 14px;
    color: #1d2756;
    font-size: 1.30rem;
    font-weight: 850;
    letter-spacing: -0.3px;
}

.nxl-ws-links {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.nxl-ws-link-item {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 11px 14px;
    border-radius: 14px;
    background: linear-gradient(180deg, #f8fffe 0%, #f1fbf8 100%);
    border: 1px solid rgba(15,143,122,0.18);
    color: #1d2756;
    text-decoration: none;
    font-size: 0.92rem;
    font-weight: 700;
    transition: all 0.20s ease;
}

.nxl-ws-link-item:hover {
    background: linear-gradient(180deg, #eefbf8 0%, #e2f7f2 100%);
    border-color: rgba(15,143,122,0.38);
    color: #0f7b6b;
    text-decoration: none;
    transform: translateX(3px);
    box-shadow: 0 4px 12px rgba(15,143,122,0.10);
}

.nxl-ws-link-icon {
    width: 36px;
    height: 36px;
    min-width: 36px;
    border-radius: 11px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: linear-gradient(135deg, #0f8f7a 0%, #16a37f 100%);
    color: #ffffff;
    font-size: 0.74rem;
    font-weight: 900;
}

.nxl-ws-link-desc {
    display: block;
    font-size: 0.73rem;
    color: #6d7f96;
    font-weight: 600;
    margin-top: 1px;
}

@media (max-width: 860px) {
    .nxl-ws-hero {
        grid-template-columns: 1fr;
    }
}

/* =========================================================
   DIGITZ AI Nexus Workspace Theme
   Finalized Blue + Teal Workspace Theme
   ========================================================= */

.nexus-ws {
    max-width: 1180px;
    margin: 0 auto;
    width: 100%;
    box-sizing: border-box;
    color: #102b67;
    font-family: inherit;
}

/* =========================
   Top Intelligence Panel
   ========================= */

.nexus-top-panel {
    position: relative;
    overflow: hidden;
    border-radius: 30px;
    padding: 30px;
    margin-bottom: 22px;
    background:
        radial-gradient(circle at 85% 18%, rgba(77, 200, 255, 0.30), transparent 30%),
        radial-gradient(circle at 92% 92%, rgba(0, 184, 148, 0.18), transparent 34%),
        linear-gradient(135deg, #082d8f 0%, #0b58d8 42%, #118fe5 78%, #33c6ec 100%);
    border: 1.5px solid rgba(77, 200, 255, 0.52);
    box-shadow:
        0 22px 52px rgba(33, 77, 187, 0.18),
        inset 0 1px 0 rgba(255, 255, 255, 0.25),
        inset 0 -30px 72px rgba(0, 42, 145, 0.16);
}

.nexus-top-panel::after {
    content: "";
    position: absolute;
    right: 0;
    bottom: 0;
    width: 42%;
    height: 7px;
    background: linear-gradient(
        90deg,
        transparent 0%,
        rgba(77, 200, 255, 0.70) 38%,
        rgba(0, 184, 148, 0.90) 100%
    );
    border-radius: 999px 0 0 0;
    box-shadow: 0 -8px 24px rgba(0, 184, 148, 0.18);
}

.nexus-top-orb {
    position: absolute;
    right: 38px;
    top: 28px;
    width: 150px;
    height: 150px;
    border-radius: 50%;
    background:
        radial-gradient(circle at 35% 30%, rgba(255, 255, 255, 0.28), transparent 34%),
        rgba(255, 255, 255, 0.08);
    border: 1px solid rgba(255, 255, 255, 0.28);
    box-shadow: inset 0 0 42px rgba(255, 255, 255, 0.18);
    display: flex;
    align-items: center;
    justify-content: center;
    color: rgba(255, 255, 255, 0.46);
    font-size: 98px;
    font-weight: 950;
    line-height: 1;
    pointer-events: none;
}

.nexus-top-content {
    position: relative;
    z-index: 2;
    max-width: 820px;
}

.nexus-kicker {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 7px 12px;
    border-radius: 999px;
    background: rgba(255, 255, 255, 0.15);
    border: 1px solid rgba(255, 255, 255, 0.34);
    color: #ffffff;
    font-size: 11px;
    font-weight: 950;
    letter-spacing: 0.10em;
    text-transform: uppercase;
    margin-bottom: 16px;
}

.nexus-kicker-dot {
    width: 8px;
    height: 8px;
    border-radius: 999px;
    background: #00b894;
    box-shadow: 0 0 18px rgba(0, 184, 148, 0.70);
}

.nexus-top-title {
    margin: 0;
    color: #ffffff;
    font-size: 40px;
    line-height: 1.12;
    font-weight: 950;
    letter-spacing: -0.045em;
    text-shadow: 0 10px 26px rgba(0, 35, 120, 0.28);
}

.nexus-top-lead {
    margin: 14px 0 0;
    max-width: 820px;
    color: rgba(255, 255, 255, 0.95);
    font-size: 17px;
    line-height: 1.55;
    font-weight: 750;
    text-shadow: 0 8px 22px rgba(0, 35, 120, 0.20);
}

.nexus-chip-row {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    margin-top: 22px;
}

.nexus-chip {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    min-height: 36px;
    padding: 8px 14px;
    border-radius: 999px;
    color: #ffffff;
    background: rgba(255, 255, 255, 0.16);
    border: 1px solid rgba(255, 255, 255, 0.50);
    font-size: 12px;
    font-weight: 900;
}

/* =========================
   Active Context Strip
   ========================= */

.nexus-context-grid {
    display: grid;
    grid-template-columns: 1.5fr repeat(3, minmax(160px, 1fr));
    gap: 12px;
    margin-bottom: 24px;
}

.nexus-context-card {
    min-height: 92px;
    padding: 18px;
    border-radius: 22px;
    background: linear-gradient(180deg, #ffffff 0%, #f8fbff 100%);
    border: 1.5px solid rgba(33, 119, 255, 0.34);
    box-shadow: 0 12px 28px rgba(33, 77, 187, 0.07);
    display: flex;
    align-items: center;
    gap: 12px;
    position: relative;
    overflow: hidden;
}

.nexus-context-card-primary {
    background:
        radial-gradient(circle at 100% 0%, rgba(77, 200, 255, 0.10), transparent 28%),
        linear-gradient(180deg, #ffffff 0%, #f8fbff 100%);
    border-color: rgba(33, 119, 255, 0.40);
    box-shadow: 0 12px 28px rgba(33, 77, 187, 0.08);
    gap: 14px;
}

.nexus-context-card-primary::before {
    content: "";
    position: absolute;
    left: 0;
    top: 0;
    bottom: 0;
    width: 5px;
    background: linear-gradient(180deg, #0b6cff, #4dc8ff);
}

.nexus-context-card-teal {
    background: linear-gradient(180deg, #ffffff 0%, #f1fffb 100%);
    border-color: rgba(0, 184, 148, 0.30);
    box-shadow: 0 12px 28px rgba(0, 184, 148, 0.08);
}

.nexus-context-card-teal-soft {
    background: linear-gradient(180deg, #ffffff 0%, #f1fffb 100%);
    border-color: rgba(0, 184, 148, 0.28);
    box-shadow: 0 12px 28px rgba(0, 184, 148, 0.06);
}

.nexus-context-icon {
    width: 42px;
    height: 42px;
    min-width: 42px;
    border-radius: 15px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #eef6ff;
    color: #0b6cff;
    font-size: 20px;
    font-weight: 950;
}

.nexus-context-icon-large {
    width: 48px;
    height: 48px;
    min-width: 48px;
    border-radius: 16px;
    color: #0b6cff;
    background: #eef6ff;
    font-size: 22px;
    border: 1px solid rgba(11, 108, 255, 0.14);
}

.nexus-context-icon-mint {
    background: #dffff6;
    color: #00b894;
}

.nexus-context-icon-teal {
    background: #ecfffb;
    color: #00b894;
}

.nexus-context-title {
    margin: 0;
    color: #102b67;
    font-size: 14px;
    font-weight: 950;
}

.nexus-context-title-large {
    font-size: 17px;
}

.nexus-context-text {
    margin: 5px 0 0;
    color: #526887;
    font-size: 12px;
    line-height: 1.45;
    font-weight: 750;
}

/* =========================
   Section Heading
   ========================= */

.nexus-section {
    display: flex;
    align-items: flex-end;
    justify-content: space-between;
    gap: 14px;
    margin: 0 0 12px;
    flex-wrap: wrap;
}

.nexus-section-badge {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 6px 10px;
    border-radius: 999px;
    background: #eef6ff;
    color: #0b60d8;
    border: 1px solid rgba(11, 108, 255, 0.18);
    font-size: 11px;
    font-weight: 950;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    margin-bottom: 8px;
}

.nexus-section-badge-teal {
    background: #ecfffb;
    color: #008c78;
    border-color: rgba(0, 184, 148, 0.22);
}

.nexus-section-title {
    margin: 0;
    color: #071d4f;
    font-size: 22px;
    line-height: 1.2;
    font-weight: 950;
    letter-spacing: -0.035em;
}

.nexus-section-title::after {
    content: "";
    display: inline-block;
    width: 36px;
    height: 4px;
    margin-left: 10px;
    border-radius: 999px;
    background: linear-gradient(90deg, #00b894, #4dc8ff);
    vertical-align: middle;
}

.nexus-section-text {
    margin: 6px 0 0;
    color: #526887;
    font-size: 13px;
    line-height: 1.45;
    font-weight: 700;
}

/* =========================
   Workspace Cards
   ========================= */

.nexus-card-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
    gap: 14px;
    margin-bottom: 24px;
}

.nexus-card {
    position: relative;
    min-height: 230px;
    padding: 22px;
    border-radius: 22px;
    background:
        radial-gradient(circle at 100% 0%, rgba(77, 163, 255, 0.16), transparent 30%),
        linear-gradient(180deg, #ffffff 0%, #f8fbff 100%);
    border: 1.5px solid rgba(33, 119, 255, 0.42);
    box-shadow:
        0 14px 32px rgba(33, 77, 187, 0.09),
        inset 0 1px 0 rgba(255, 255, 255, 0.78);
    color: inherit;
    text-decoration: none;
    display: block;
    overflow: hidden;
}

.nexus-card:hover {
    color: inherit;
    text-decoration: none;
}

.nexus-card::before {
    content: "";
    position: absolute;
    left: 0;
    right: 0;
    top: 0;
    height: 5px;
    background: linear-gradient(90deg, #0b6cff, #4dc8ff);
}

.nexus-card-purple::before {
    background: linear-gradient(90deg, #725cff, #0b6cff);
}

.nexus-card-teal::before {
    background: linear-gradient(90deg, #00b894, #4dc8ff);
}

.nexus-card-teal-bg {
    background: linear-gradient(180deg, #ffffff 0%, #f1fffb 100%);
    border-color: rgba(0, 184, 148, 0.32);
    box-shadow:
        0 14px 32px rgba(0, 184, 148, 0.08),
        inset 0 1px 0 rgba(255, 255, 255, 0.78);
}

.nexus-card-head {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    gap: 12px;
    margin-bottom: 14px;
}

.nexus-card-icon {
    width: 52px;
    height: 52px;
    border-radius: 18px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 23px;
    font-weight: 950;
    color: #0b6cff;
    background: #eef6ff;
}

.nexus-card-icon-purple {
    color: #725cff;
    background: #f4f1ff;
}

.nexus-card-icon-teal {
    color: #00b894;
    background: #ecfffb;
}

.nexus-card-arrow {
    width: 32px;
    height: 32px;
    border-radius: 999px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #214dbb;
    background: #ffffff;
    border: 1.5px solid rgba(33, 119, 255, 0.35);
    font-weight: 950;
}

.nexus-card-arrow-teal {
    color: #008c78;
    border-color: rgba(0, 184, 148, 0.32);
}

.nexus-card-title {
    margin: 0;
    color: #102b67;
    font-size: 18px;
    font-weight: 950;
}

.nexus-card-subtitle {
    margin-top: 4px;
    color: #264579;
    font-size: 13px;
    font-weight: 900;
}

.nexus-card-subtitle-teal {
    color: #008c78;
}

.nexus-card-text {
    margin: 7px 0 0;
    color: #526887;
    font-size: 12px;
    line-height: 1.55;
    font-weight: 700;
}

.nexus-tag-row {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    margin-top: 18px;
}

.nexus-tag {
    padding: 7px 11px;
    border-radius: 999px;
    background: #f3f8ff;
    color: #0b60d8;
    font-size: 11px;
    font-weight: 900;
    border: 1px solid rgba(33, 119, 255, 0.18);
}

.nexus-tag-purple {
    background: #f5f2ff;
    color: #5e49d8;
    border-color: transparent;
}

.nexus-tag-teal {
    background: #edfffb;
    color: #008c78;
    border-color: transparent;
}

.nexus-tag-teal-strong {
    background: #ecfffb;
    color: #008c78;
    border-color: transparent;
}

/* =========================
   Capabilities
   ========================= */

.nexus-capability-panel {
    padding: 22px;
    border-radius: 24px;
    background:
        radial-gradient(circle at 100% 0%, rgba(0, 184, 148, 0.06), transparent 24%),
        #ffffff;
    border: 1.5px solid rgba(33, 119, 255, 0.42);
    box-shadow:
        0 14px 32px rgba(33, 77, 187, 0.09),
        inset 0 1px 0 rgba(255, 255, 255, 0.78);
}

.nexus-capability-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(190px, 1fr));
    gap: 12px;
}

.nexus-capability-tile {
    display: flex;
    align-items: center;
    gap: 12px;
    min-height: 72px;
    padding: 14px;
    border-radius: 16px;
    background: #ffffff;
    border: 1.5px solid rgba(33, 119, 255, 0.30);
}

.nexus-capability-tile-teal {
    background: #f1fffb;
    border-color: rgba(0, 184, 148, 0.30);
}

.nexus-capability-icon {
    width: 38px;
    height: 38px;
    min-width: 38px;
    border-radius: 13px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #eef6ff;
    color: #0b6cff;
    font-size: 18px;
    font-weight: 950;
}

.nexus-capability-icon-teal {
    background: #dffff6;
    color: #00b894;
}

.nexus-capability-text {
    margin: 0;
    color: #102b67;
    font-size: 12px;
    line-height: 1.35;
    font-weight: 850;
}

/* =========================
   Responsive
   ========================= */

@media (max-width: 900px) {
    .nexus-context-grid {
        grid-template-columns: 1fr 1fr;
    }

    .nexus-top-orb {
        opacity: 0.35;
        right: 16px;
    }
}

@media (max-width: 640px) {
    .nexus-top-panel {
        padding: 24px;
    }

    .nexus-top-title {
        font-size: 32px;
    }

    .nexus-context-grid,
    .nexus-card-grid,
    .nexus-capability-grid {
        grid-template-columns: 1fr;
    }
}

/* Link behavior for updated Nexus Live workspace cards */
.nexus-context-card,
.nexus-capability-tile {
    color: inherit;
    text-decoration: none;
}

.nexus-context-card:hover,
.nexus-context-card:focus,
.nexus-capability-tile:hover,
.nexus-capability-tile:focus {
    color: inherit;
    text-decoration: none;
}

.nexus-card:focus,
.nexus-context-card:focus,
.nexus-capability-tile:focus {
    outline: 2px solid rgba(11, 108, 255, 0.34);
    outline-offset: 3px;
}

