    grid-template-columns: repeat(auto-fit, minmax(190px, 1fr));
    gap: 12px;
}

.nexus-capability-tile {
    display: flex;
    align-items: center;
    gap: 12px;
    min-height: 72px;
    padding: 14px;
    border-radius: 16px;
    background: #ffffff;
    border: 1.5px solid rgba(33, 119, 255, 0.30);
}

.nexus-capability-tile-teal {
    background: #f1fffb;
    border-color: rgba(0, 184, 148, 0.30);
}

.nexus-capability-icon {
    width: 38px;
    height: 38px;
    min-width: 38px;
    border-radius: 13px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #eef6ff;
    color: #0b6cff;
    font-size: 18px;
    font-weight: 950;
}

.nexus-capability-icon-teal {
    background: #dffff6;
    color: #00b894;
}

.nexus-capability-text {
    margin: 0;
    color: #102b67;
    font-size: 12px;
    line-height: 1.35;
    font-weight: 850;
}

/* =========================
   Responsive
   ========================= */

@media (max-width: 900px) {
    .nexus-context-grid {
        grid-template-columns: 1fr 1fr;
    }

    .nexus-top-orb {
        opacity: 0.35;
        right: 16px;
    }
}

@media (max-width: 640px) {
    .nexus-top-panel {
        padding: 24px;
    }

    .nexus-top-title {
        font-size: 32px;
    }

    .nexus-context-grid,
    .nexus-card-grid,
    .nexus-capability-grid {
        grid-template-columns: 1fr;
    }
}

/* ================================================
   NEXUS NEXY WORKSPACE — Role-Based AI Operator
   Orange accent variant over the shared Nexus theme
   ================================================ */

.nxl-ws-hero {
    display: grid;
    grid-template-columns: 1.35fr 1fr;
    gap: 16px;
    margin-bottom: 0;
}

.nxl-ws-panel {
    position: relative;
    overflow: hidden;
    padding: 24px 26px 22px;
    border-radius: 20px;
    background: #ffffff;
    border: 1px solid rgba(33,77,187,0.13);
    box-shadow: 0 8px 24px rgba(33,77,187,0.08), inset 0 1px 0 rgba(255,255,255,0.90);
}

.nxl-ws-panel::before {
    content: "";
    position: absolute;
    left: 0;
    right: 0;
    top: 0;
    height: 5px;
    border-radius: 20px 20px 0 0;
}

.nxl-ws-panel > * {
    position: relative;
    z-index: 1;
}

/* Blue left panel (identity) */
.nxl-ws-panel-blue {
    border-top: 4px solid #214dbb;
    background:
        linear-gradient(135deg, rgba(33,77,187,0.05) 0%, rgba(255,255,255,0) 40%),
        #ffffff;
}

.nxl-ws-panel-blue::before {
    background: linear-gradient(90deg, #214dbb 0%, #4d75ff 55%, #e07328 100%);
}

/* Orange right panel (operator console) */
.nxl-ws-panel-orange {
    border-top: 4px solid #e07328;
    border-color: rgba(224,115,40,0.20);
    background:
        linear-gradient(135deg, rgba(224,115,40,0.055) 0%, rgba(255,255,255,0) 40%),
        #ffffff;
}

.nxl-ws-panel-orange::before {
    background: linear-gradient(90deg, #e07328 0%, #e89545 55%, #214dbb 100%);
}

/* Teal panel */
.nxl-ws-panel-teal {
    border-top: 4px solid #0f8f7a;
    border-color: rgba(15,143,122,0.20);
    background:
        linear-gradient(135deg, rgba(15,143,122,0.055) 0%, rgba(255,255,255,0) 40%),
        #ffffff;
}

.nxl-ws-panel-teal::before {
    background: linear-gradient(90deg, #0f8f7a 0%, #16a37f 55%, #e0a62f 100%);
}

/* Kicker pill */
.nxl-ws-kicker {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    margin-bottom: 14px;
    padding: 6px 12px;
    border-radius: 999px;
    background: #ffffff;
    border: 1px solid rgba(33,77,187,0.18);
    color: #214dbb;
    font-size: 0.76rem;
    font-weight: 800;
    letter-spacing: 0.12em;
    text-transform: uppercase;
}

.nxl-ws-kicker-teal {
    border-color: rgba(15,143,122,0.22);
    color: #0f7b6b;
}

.nxl-ws-kicker-orange {
    border-color: rgba(224,115,40,0.24);
    color: #b85a18;
}

/* Title row */
.nxl-ws-title-row {
    display: flex;
    align-items: center;
    gap: 14px;
    margin-bottom: 14px;
}

.nxl-ws-icon-box {
    width: 52px;
    height: 52px;
    border-radius: 16px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #214dbb;
    border: 1px solid rgba(255,255,255,0.30);
    box-shadow: 0 10px 22px rgba(33,77,187,0.22);
    flex-shrink: 0;
}

.nxl-ws-icon-box svg {
    width: 30px;
    height: 30px;
}

.nxl-ws-h1 {
    margin: 0;
    color: #1d2756;
    font-size: 1.95rem;
    line-height: 1.14;
    font-weight: 850;
    letter-spacing: -0.6px;
}

.nxl-ws-lead {
    max-width: 680px;
    color: #5f6c8c;
    font-size: 0.96rem;
    line-height: 1.70;
    margin: 0 0 16px;
}

.nxl-ws-chips {
    display: flex;
    flex-wrap: wrap;
    gap: 7px;
}

.nxl-ws-chip {
    padding: 5px 11px;
    border-radius: 999px;
    background: linear-gradient(180deg, #f3f8ff 0%, #eaf2ff 100%);
    border: 1px solid rgba(33,77,187,0.14);
    color: #214dbb;
    font-size: 0.76rem;
    font-weight: 700;
}

.nxl-ws-chip-live {
    background: linear-gradient(180deg, #f0fff8 0%, #e2fff3 100%);
    border-color: rgba(0,184,148,0.22);
    color: #007a62;
}

/* Right panel — links */
.nxl-ws-panel-title {
    margin: 0 0 14px;
    color: #1d2756;
    font-size: 1.30rem;
    font-weight: 850;
    letter-spacing: -0.3px;
}

.nxl-ws-links {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

/* Teal link-item (default) */
.nxl-ws-link-item {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 11px 14px;
    border-radius: 14px;
    background: linear-gradient(180deg, #f8fffe 0%, #f1fbf8 100%);
    border: 1px solid rgba(15,143,122,0.18);
    color: #1d2756;
    text-decoration: none;
    font-size: 0.92rem;
    font-weight: 700;
    transition: all 0.20s ease;
}

.nxl-ws-link-item:hover {
    background: linear-gradient(180deg, #eefbf8 0%, #e2f7f2 100%);
    border-color: rgba(15,143,122,0.38);
    color: #0f7b6b;
    text-decoration: none;
    transform: translateX(3px);
    box-shadow: 0 4px 12px rgba(15,143,122,0.10);
}

.nxl-ws-link-icon {
    width: 36px;
    height: 36px;
    min-width: 36px;
    border-radius: 11px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: linear-gradient(135deg, #0f8f7a 0%, #16a37f 100%);
    color: #ffffff;
    font-size: 0.74rem;
    font-weight: 900;
}

/* Orange link-item variant */
.nxl-ws-link-item-orange {
    background: linear-gradient(180deg, #fffaf6 0%, #fff4ec 100%);
    border-color: rgba(224,115,40,0.18);
}

.nxl-ws-link-item-orange:hover {
    background: linear-gradient(180deg, #fff4ea 0%, #ffe8d6 100%);
    border-color: rgba(224,115,40,0.38);
    color: #a84e0d;
    transform: translateX(3px);
    box-shadow: 0 4px 12px rgba(224,115,40,0.12);
}

.nxl-ws-link-icon-orange {
    background: linear-gradient(135deg, #e07328 0%, #e89545 100%);
    color: #ffffff;
}

.nxl-ws-link-desc {
    display: block;
    font-size: 0.73rem;
    color: #6d7f96;
    font-weight: 600;
    margin-top: 1px;
}

@media (max-width: 860px) {
    .nxl-ws-hero {
        grid-template-columns: 1fr;
    }
}

/* =========================================================
   DIGITZ AI Nexus Workspace Theme — Base
   ========================================================= */

.nexus-ws {
    max-width: 1180px;
    margin: 0 auto;
    width: 100%;
    box-sizing: border-box;
    color: #102b67;
    font-family: inherit;
}

/* =========================
   Context Strip (3-col for Nexy)
   ========================= */

.nexus-context-grid {
    display: grid;
    grid-template-columns: 1.5fr repeat(3, minmax(160px, 1fr));
    gap: 12px;
    margin-bottom: 24px;
}

.nexus-context-grid-nexy {
    grid-template-columns: 1.4fr 1fr 1fr;
}

.nexus-context-card {
    min-height: 92px;
    padding: 18px;
    border-radius: 22px;
    background: linear-gradient(180deg, #ffffff 0%, #f8fbff 100%);
    border: 1.5px solid rgba(33, 119, 255, 0.34);
    box-shadow: 0 12px 28px rgba(33, 77, 187, 0.07);
    display: flex;
    align-items: center;
    gap: 12px;
    position: relative;
    overflow: hidden;
    color: inherit;
    text-decoration: none;
}

.nexus-context-card:hover,
.nexus-context-card:focus {
    color: inherit;
    text-decoration: none;
}

.nexus-context-card-primary {
    background:
        radial-gradient(circle at 100% 0%, rgba(224,115,40,0.08), transparent 28%),
        linear-gradient(180deg, #ffffff 0%, #fff8f4 100%);
    border-color: rgba(224,115,40,0.35);
    box-shadow: 0 12px 28px rgba(224,115,40,0.08);
    gap: 14px;
}

.nexus-context-card-primary::before {
    content: "";
    position: absolute;
    left: 0;
    top: 0;
    bottom: 0;
    width: 5px;
    background: linear-gradient(180deg, #e07328, #e89545);
}

.nexus-context-card-teal {
    background: linear-gradient(180deg, #ffffff 0%, #f1fffb 100%);
    border-color: rgba(0, 184, 148, 0.30);
    box-shadow: 0 12px 28px rgba(0, 184, 148, 0.08);
}

.nexus-context-icon {
    width: 42px;
    height: 42px;
    min-width: 42px;
    border-radius: 15px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #eef6ff;
    color: #0b6cff;
    font-size: 20px;
    font-weight: 950;
}

.nexus-context-icon-large {
    width: 48px;
    height: 48px;
    min-width: 48px;
    border-radius: 16px;
    font-size: 22px;
    border: 1px solid rgba(11, 108, 255, 0.14);
}

.nexus-context-icon-mint {
    background: #dffff6;
    color: #00b894;
}

.nexus-context-icon-teal {
    background: #ecfffb;
    color: #00b894;
}

.nexus-context-icon-orange {
    background: #fff3ea;
    color: #c05a14;
    border: 1px solid rgba(224,115,40,0.16);
}

.nexus-context-title {
    margin: 0;
    color: #102b67;
    font-size: 14px;
    font-weight: 950;
}

.nexus-context-title-large {
    font-size: 17px;
}

.nexus-context-text {
    margin: 5px 0 0;
    color: #526887;
    font-size: 12px;
    line-height: 1.45;
    font-weight: 750;
}

/* =========================
   Section Headings
   ========================= */

.nexus-section {
    display: flex;
    align-items: flex-end;
    justify-content: space-between;
    gap: 14px;
    margin: 0 0 12px;
    flex-wrap: wrap;
}

.nexus-section-badge {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 6px 10px;
    border-radius: 999px;
    background: #eef6ff;
    color: #0b60d8;
    border: 1px solid rgba(11, 108, 255, 0.18);
    font-size: 11px;
    font-weight: 950;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    margin-bottom: 8px;
}

.nexus-section-badge-teal {
    background: #ecfffb;
    color: #008c78;
    border-color: rgba(0, 184, 148, 0.22);
}

.nexus-section-badge-orange {
    background: #fff4ec;
    color: #b85a18;
    border-color: rgba(224,115,40,0.24);
}

.nexus-section-title {
    margin: 0;
    color: #071d4f;
    font-size: 22px;
    line-height: 1.2;
    font-weight: 950;
    letter-spacing: -0.035em;
}

.nexus-section-title::after {
    content: "";
    display: inline-block;
    width: 36px;
    height: 4px;
    margin-left: 10px;
    border-radius: 999px;
    background: linear-gradient(90deg, #e07328, #e89545);
    vertical-align: middle;
}

.nexus-section-text {
    margin: 6px 0 0;
    color: #526887;
    font-size: 13px;
    line-height: 1.45;
    font-weight: 700;
}

/* =========================
   Workspace Cards
   ========================= */

.nexus-card-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
    gap: 14px;
    margin-bottom: 24px;
}

.nexus-card {
    position: relative;
    min-height: 230px;
    padding: 22px;
    border-radius: 22px;
    background:
        radial-gradient(circle at 100% 0%, rgba(77, 163, 255, 0.16), transparent 30%),
        linear-gradient(180deg, #ffffff 0%, #f8fbff 100%);
    border: 1.5px solid rgba(33, 119, 255, 0.42);
    box-shadow:
        0 14px 32px rgba(33, 77, 187, 0.09),
        inset 0 1px 0 rgba(255, 255, 255, 0.78);
    color: inherit;
    text-decoration: none;
    display: block;
    overflow: hidden;
}

.nexus-card:hover,
.nexus-card:focus {
    color: inherit;
    text-decoration: none;
}

.nexus-card::before {
    content: "";
    position: absolute;
    left: 0;
    right: 0;
    top: 0;
    height: 5px;
    background: linear-gradient(90deg, #0b6cff, #4dc8ff);
}

.nexus-card-purple::before {
    background: linear-gradient(90deg, #725cff, #0b6cff);
}

.nexus-card-teal::before {
    background: linear-gradient(90deg, #00b894, #4dc8ff);
}

/* Orange accent card */
.nexus-card-orange-accent {
    background:
        radial-gradient(circle at 100% 0%, rgba(224,115,40,0.10), transparent 30%),
        linear-gradient(180deg, #ffffff 0%, #fff8f3 100%);
    border-color: rgba(224,115,40,0.38);
    box-shadow:
        0 14px 32px rgba(224,115,40,0.08),
        inset 0 1px 0 rgba(255,255,255,0.78);
}

.nexus-card-orange-accent::before {
    background: linear-gradient(90deg, #e07328, #e89545);
}

.nexus-card-teal-bg {
    background: linear-gradient(180deg, #ffffff 0%, #f1fffb 100%);
    border-color: rgba(0, 184, 148, 0.32);
    box-shadow:
        0 14px 32px rgba(0, 184, 148, 0.08),
        inset 0 1px 0 rgba(255, 255, 255, 0.78);
}

.nexus-card-head {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    gap: 12px;
    margin-bottom: 14px;
}

.nexus-card-icon {
    width: 52px;
    height: 52px;
    border-radius: 18px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 23px;
    font-weight: 950;
    color: #0b6cff;
    background: #eef6ff;
}

.nexus-card-icon-purple {
    color: #725cff;
    background: #f4f1ff;
}

.nexus-card-icon-teal {
    color: #00b894;
    background: #ecfffb;
}

.nexus-card-icon-orange {
    color: #c05a14;
    background: #fff3ea;
}

.nexus-card-arrow {
    width: 32px;
    height: 32px;
    border-radius: 999px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #214dbb;
    background: #ffffff;
    border: 1.5px solid rgba(33, 119, 255, 0.35);
    font-weight: 950;
}

.nexus-card-arrow-teal {
    color: #008c78;
    border-color: rgba(0, 184, 148, 0.32);
}

.nexus-card-arrow-orange {
    color: #b85a18;
    border-color: rgba(224,115,40,0.30);
}

.nexus-card-title {
    margin: 0;
    color: #102b67;
    font-size: 18px;
    font-weight: 950;
}

.nexus-card-subtitle {
    margin-top: 4px;
    color: #264579;
    font-size: 13px;
    font-weight: 900;
}

.nexus-card-subtitle-teal {
    color: #008c78;
}

.nexus-card-subtitle-orange {
    color: #b85a18;
}

.nexus-card-text {
    margin: 7px 0 0;
    color: #526887;
    font-size: 12px;
    line-height: 1.55;
    font-weight: 700;
}

.nexus-tag-row {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    margin-top: 18px;
}

.nexus-tag {
    padding: 7px 11px;
    border-radius: 999px;
    background: #f3f8ff;
    color: #0b60d8;
    font-size: 11px;
    font-weight: 900;
    border: 1px solid rgba(33, 119, 255, 0.18);
}

.nexus-tag-purple {
    background: #f5f2ff;
    color: #5e49d8;
    border-color: transparent;
}

.nexus-tag-teal {
    background: #edfffb;
    color: #008c78;
    border-color: transparent;
}

.nexus-tag-orange {
    background: #fff4ec;
    color: #b85a18;
    border-color: transparent;
}

/* =========================
   Capability Panel
   ========================= */

.nexus-capability-panel {
    padding: 22px;
    border-radius: 24px;
    background:
        radial-gradient(circle at 100% 0%, rgba(224,115,40,0.05), transparent 24%),
        #ffffff;
    border: 1.5px solid rgba(33, 119, 255, 0.42);
    box-shadow:
        0 14px 32px rgba(33, 77, 187, 0.09),
        inset 0 1px 0 rgba(255, 255, 255, 0.78);
}

.nexus-capability-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(190px, 1fr));
    gap: 12px;
}

.nexus-capability-tile {
    display: flex;
    align-items: center;
    gap: 12px;
    min-height: 72px;
    padding: 14px;
    border-radius: 16px;
    background: #ffffff;
    border: 1.5px solid rgba(33, 119, 255, 0.30);
    color: inherit;
    text-decoration: none;
}

.nexus-capability-tile:hover,
.nexus-capability-tile:focus {
    color: inherit;
    text-decoration: none;
}

.nexus-capability-tile:focus,
.nexus-card:focus,
.nexus-context-card:focus {
    outline: 2px solid rgba(224,115,40,0.34);
    outline-offset: 3px;
}

.nexus-capability-tile-teal {
    background: #f1fffb;
    border-color: rgba(0, 184, 148, 0.30);
}

.nexus-capability-tile-orange {
    background: #fff8f3;
    border-color: rgba(224,115,40,0.28);
}

.nexus-capability-icon {
    width: 38px;
    height: 38px;
    min-width: 38px;
    border-radius: 13px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #eef6ff;
    color: #0b6cff;
    font-size: 18px;
    font-weight: 950;
}

.nexus-capability-icon-teal {
    background: #dffff6;
    color: #00b894;
}

.nexus-capability-icon-orange {
    background: #fff3ea;
    color: #c05a14;
}

.nexus-capability-text {
    margin: 0;
    color: #102b67;
    font-size: 12px;
    line-height: 1.35;
    font-weight: 850;
}

/* =========================
   Responsive
   ========================= */

@media (max-width: 900px) {
    .nexus-context-grid,
    .nexus-context-grid-nexy {
        grid-template-columns: 1fr 1fr;
    }
}

@media (max-width: 640px) {
    .nexus-context-grid,
    .nexus-context-grid-nexy,
    .nexus-card-grid,
    .nexus-capability-grid {
        grid-template-columns: 1fr;
    }
}
